'use client'

import useSWR, { preload } from 'swr'
import type { MarketSummary, MarketDetail } from './market-types'
import type { LeaderboardEntry } from './leaderboard'

export const LEADERBOARD_KEY = '/api/leaderboard'
export const AUTH_KEY = '/api/auth/me'
export const marketKey = (id: string) => `/api/markets/${id}`

export const fetcher = async (url: string) => {
  const response = await fetch(url, {
    credentials: 'same-origin',
  })

  if (!response.ok) {
    throw new Error(`Request failed for ${url}: ${response.status}`)
  }

  return response.json()
}

// Cache config
const SWRCONFIG = {
  refreshInterval: 0,
  revalidateOnFocus: false,
  revalidateIfStale: false,
  keepPreviousData: true,
  dedupingInterval: 30000,
}

export function useMarkets(search?: string, status?: string) {
  const params = new URLSearchParams()
  if (search) params.set('search', search)
  if (status && status !== 'all') params.set('status', status)
  const key = `/api/markets?${params}`

  return useSWR<MarketSummary[]>(key, fetcher, {
    ...SWRCONFIG,
    revalidateOnFocus: true,
    refreshInterval: 30000, // Refresh every 30s
  })
}

export function useMarket(id: string) {
  return useSWR<MarketDetail>(id && id !== '' ? marketKey(id) : null, fetcher, {
    ...SWRCONFIG,
    revalidateOnFocus: true,
    refreshInterval: 15000,
  })
}

export function useLeaderboard() {
  return useSWR<LeaderboardEntry[]>(LEADERBOARD_KEY, fetcher, {
    ...SWRCONFIG,
    refreshInterval: 60000, // Refresh every 60s
  })
}

export function useTrendingMarkets() {
  return useSWR<MarketSummary[]>('/api/markets?status=active', fetcher, {
    ...SWRCONFIG,
    refreshInterval: 30000,
  })
}

export function useAuth() {
  return useSWR<{ user?: { id: string; name: string; coins: number; heldCoins: number } }>(
    AUTH_KEY,
    fetcher,
    SWRCONFIG
  )
}

export function preloadLeaderboardPageData() {
  preload(LEADERBOARD_KEY, fetcher)
}

export function preloadMarketPageData(id: string) {
  if (!id) return
  preload(marketKey(id), fetcher)
}

export function mutateMarkets() {
  return fetch('/api/markets').then((r) => r.json())
}

export function mutateMarket(id: string) {
  return fetch(`/api/markets/${id}`).then((r) => r.json())
}

import { cookies } from 'next/headers'
import { prisma } from '@/lib/prisma'
export {
  SESSION_COOKIE,
  SESSION_MAX_AGE,
  createSessionToken,
  hashPassword,
  validatePassword,
  validateUsername,
  verifyPassword,
} from '@/lib/auth-core'
import { SESSION_COOKIE, SESSION_MAX_AGE, createSessionToken, verifySessionToken } from '@/lib/auth-core'

export async function setSession(user: { id: string; name: string }) {
  const cookieStore = await cookies()
  cookieStore.set(SESSION_COOKIE, createSessionToken({ userId: user.id, name: user.name }), {
    httpOnly: true,
    sameSite: 'lax',
    secure: process.env.NODE_ENV === 'production',
    path: '/',
    maxAge: SESSION_MAX_AGE,
  })
}

export async function clearSession() {
  const cookieStore = await cookies()
  cookieStore.delete(SESSION_COOKIE)
}

export async function getSessionUser() {
  const cookieStore = await cookies()
  const token = cookieStore.get(SESSION_COOKIE)?.value
  const payload = verifySessionToken(token)
  if (!payload) return null

  return prisma.user.findUnique({
    where: { id: payload.userId },
    select: { id: true, name: true, coins: true, heldCoins: true },
  })
}

import { Elysia } from 'elysia'
import { hashPassword, validatePassword, validateUsername, verifyPassword } from '@/lib/auth-core'
import { getUserWithBalanceById } from '@/lib/balances'
import { prisma } from '@/lib/prisma'
import { asObject, getString, noStoreHeaders } from '@/server/http'
import { clearSessionCookie, createSessionCookie, getSessionUser } from '@/server/session'

export const authRoutes = new Elysia()
  .get('/api/auth/me', async ({ request, set }) => {
    const user = await getSessionUser(request)
    set.headers = noStoreHeaders()
    return { user }
  })
  .post('/api/auth/sign-in', async ({ body, set }) => {
    try {
      const data = asObject(body)
      const name = validateUsername(getString(data.username))
      const user = await prisma.user.findUnique({ where: { name } })

      if (!user || !verifyPassword(getString(data.password), user.passwordHash)) {
        set.status = 401
        return { error: 'Invalid username or password' }
      }

      set.headers['Set-Cookie'] = createSessionCookie(user)
      return await getUserWithBalanceById(user.id)
    } catch (error) {
      set.status = 400
      return { error: error instanceof Error ? error.message : 'Failed to sign in' }
    }
  })
  .post('/api/auth/sign-up', async ({ body, set }) => {
    try {
      const data = asObject(body)
      const password = getString(data.password)
      const name = validateUsername(getString(data.username))
      validatePassword(password)
      if (data.confirmPassword !== undefined && password !== data.confirmPassword) {
        set.status = 400
        return { error: 'Passwords do not match' }
      }

      const existing = await prisma.user.findUnique({ where: { name } })
      if (existing?.passwordHash) {
        set.status = 409
        return { error: 'Username is already taken' }
      }

      const user = existing
        ? await prisma.user.update({
            where: { id: existing.id },
            data: { passwordHash: hashPassword(password) },
          })
        : await prisma.user.create({
            data: { name, passwordHash: hashPassword(password), coins: 10000, heldCoins: 0 },
          })

      set.headers['Set-Cookie'] = createSessionCookie(user)
      return await getUserWithBalanceById(user.id)
    } catch (error) {
      set.status = 400
      return { error: error instanceof Error ? error.message : 'Failed to sign up' }
    }
  })
  .post('/api/auth/sign-out', ({ set }) => {
    set.headers['Set-Cookie'] = clearSessionCookie()
    return { ok: true }
  })

