import { Input } from '@/components/ui/input'
import { Button } from '@/components/ui/button'
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { Search, TrendingUp, Activity, CheckCircle } from 'lucide-react'
import { TrendingSidebar } from '@/components/trending-sidebar'
import { preloadMarketPageData, useMarkets, useAuth } from '@/lib/use-data'

export default function Home() {
  const canSeedSampleData = process.env.NODE_ENV !== 'production'
  const router = useRouter()
  const [search, setSearch] = useState('')
  const [status, setStatus] = useState('all')
  const { data: markets, isLoading: loading } = useMarkets(search, status)
  const { data: authData } = useAuth()
  const currentUser = authData?.user

  const handleQuickBet = (marketId: string, choice: 'YES' | 'NO') => {
    if (!currentUser) {
      window.dispatchEvent(new Event('open-auth-dialog'))
      return
    }
    preloadMarketPageData(marketId)
    router.push(`/market/${marketId}?choice=${choice}`)
  }

  const seedData = async () => {
    await fetch('/api/seed', { method: 'POST' })
    window.location.reload()
  }

  return (
    <div className="max-w-[1400px] mx-auto px-4 py-6">
      <div className="grid grid-cols-1 gap-6 lg:grid-cols-12">
        {/* Main Content */}
        <div className="lg:col-span-9">
          {/* Section Header */}
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-2">
              <TrendingUp className="w-5 h-5 text-[#3fb950]" />
              <h1 className="text-lg font-bold text-white">Trending</h1>
            </div>
            <Tabs value={status} onValueChange={setStatus}>
              <TabsList className="bg-[#161b22] border border-[#30363d] h-8">
                <TabsTrigger value="all" className="data-[state=active]:bg-[#21262d] text-xs h-6">
                  <Activity className="w-3 h-3 mr-1" />
                  All
                </TabsTrigger>
                <TabsTrigger value="active" className="data-[state=active]:bg-[#21262d] text-xs h-6">
                  <TrendingUp className="w-3 h-3 mr-1" />
                  Active
                </TabsTrigger>
                <TabsTrigger value="resolved" className="data-[state=active]:bg-[#21262d] text-xs h-6">
                  <CheckCircle className="w-3 h-3 mr-1" />
                  Resolved
                </TabsTrigger>
              </TabsList>
            </Tabs>
          </div>

          {/* Search */}
          <div className="relative mb-4 hidden md:block">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-[#484f58]" />
            <Input
              placeholder="Search markets..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="pl-9 bg-[#161b22] border-[#30363d] text-white h-9 text-sm"
            />
          </div>

          {/* Markets Grid */}
          {loading ? (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {Array.from({ length: 6 }).map((_, i) => (
                <div key={i} className="bg-[#161b22] border border-[#30363d] rounded-xl h-48 animate-pulse" />
              ))}
            </div>
          ) : !markets || markets.length === 0 ? (
            <div className="text-center py-20">
              <p className="text-[#484f58] text-lg mb-4">No markets found</p>
              {canSeedSampleData ? (
                <Button onClick={seedData} className="bg-[#238636] hover:bg-[#2ea043] text-white font-semibold">
                  Load Sample Markets
                </Button>
              ) : null}
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {markets.map((market) => (
                <MarketCard key={market.id} market={market} onQuickBet={handleQuickBet} />
              ))}
            </div>
          )}
        </div>

        {/* Sidebar */}
        <div className="lg:col-span-3">
          <div className="sticky top-20">
            <TrendingSidebar />
          </div>
        </div>
      </div>
    </div>
  )
}

