// Lazy load create market dialog
const CreateMarketDialog = lazy(() => import('./create-market-dialog').then(m => ({ default: m.CreateMarketDialog })))

export function Navbar() {
  const router = useRouter()
  const { data: authData, mutate: refreshAuth } = useAuth()
  const user = authData?.user

  const [inputName, setInputName] = useState('')
  const [password, setPassword] = useState('')
  const [confirmPassword, setConfirmPassword] = useState('')
  const [authMode, setAuthMode] = useState<'sign-in' | 'sign-up'>('sign-in')
  const [authError, setAuthError] = useState('')
  const [open, setOpen] = useState(false)
  const [accountOpen, setAccountOpen] = useState(false)
  const [createOpen, setCreateOpen] = useState(false)

  useEffect(() => {
    preloadLeaderboardPageData()
    router.prefetch('/leaderboard')
  }, [router])

  const handleAuth = async () => {
    setAuthError('')
    if (!inputName.trim() || !password) {
      setAuthError('Enter your username and password')
      return
    }
    if (authMode === 'sign-up' && password !== confirmPassword) {
      setAuthError('Passwords do not match')
      return
    }

    const res = await fetch(`/api/auth/${authMode}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ username: inputName, password, confirmPassword }),
    })
    const data = await res.json()
    if (res.ok) {
      setPassword('')
      setConfirmPassword('')
      setOpen(false)
      refreshAuth()
      window.dispatchEvent(new Event('auth-state-changed'))
    } else {
      setAuthError(data.error || 'Authentication failed')
    }
  }

  const handleSignOut = async () => {
    await fetch('/api/auth/sign-out', { method: 'POST' })
    refreshAuth()
