'use client'

import { useState, useEffect, Suspense, lazy } from 'react'
import { useParams, useSearchParams } from 'next/navigation'
import Link from 'next/link'
import { Button } from '@/components/ui/button'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { ArrowLeft, TrendingUp, TrendingDown, Clock, Coins, User, CheckCircle, XCircle } from 'lucide-react'
import { setAuthState, useMarket, useAuth } from '@/lib/use-data'
import type { MarketDetail } from '@/lib/market-types'

// Lazy load the chart component (heavy)
const PriceChart = lazy(() => import('@/components/price-chart').then(m => ({ default: m.PriceChart })))

export default function MarketPage() {
  const { id } = useParams()
  const searchParams = useSearchParams()
  const marketId = Array.isArray(id) ? id[0] : (id || '')
  const { data: market, error, isLoading, mutate: refreshMarket } = useMarket(marketId)
  const { data: authData, mutate: refreshAuth } = useAuth()
  const currentUser = authData?.user

  const [betChoice, setBetChoice] = useState<'YES' | 'NO'>('YES')
  const [betCoins, setBetCoins] = useState('')
  const [betting, setBetting] = useState(false)
  const [activeTab, setActiveTab] = useState('chart')
  const [activityBets, setActivityBets] = useState<MarketDetail['bets']>([])
  const [nextBetsCursor, setNextBetsCursor] = useState<string | null>(null)
  const [loadingMoreBets, setLoadingMoreBets] = useState(false)

  useEffect(() => {
    const side = searchParams.get('choice')
    if (side === 'YES' || side === 'NO') {
      setBetChoice(side)
    }
  }, [searchParams])

  useEffect(() => {
    setActivityBets(market?.bets ?? [])
    setNextBetsCursor(market?.betsNextCursor ?? null)
  }, [market?.bets, market?.betsNextCursor])

  const loadMoreBets = async () => {
    if (!marketId || !nextBetsCursor || loadingMoreBets) return

    setLoadingMoreBets(true)
    try {
      const params = new URLSearchParams({
        cursor: nextBetsCursor,
      })
      const res = await fetch(`/api/markets/${marketId}/bets?${params}`, {
        credentials: 'same-origin',
      })
      if (!res.ok) throw new Error(`Failed to load more bets: ${res.status}`)
      const page = await res.json() as {
        bets: MarketDetail['bets']
        nextCursor: string | null
      }
      setActivityBets((current) => [...current, ...page.bets])
      setNextBetsCursor(page.nextCursor)
    } catch (error) {
      console.error(error)
      alert('Failed to load more bets')
    } finally {
      setLoadingMoreBets(false)
    }
  }

  const placeBet = async () => {
    if (!currentUser) {
      window.dispatchEvent(new Event('open-auth-dialog'))
      return
    }
    const coins = parseFloat(betCoins)
    if (!coins || coins <= 0) {
      alert('Please enter a valid amount of coins')
      return
    }

    const submittedChoice = activeUserSide ?? betChoice
    setBetting(true)
    try {
      const res = await fetch('/api/bets', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          marketId,
          coins,
          choice: submittedChoice,
        }),
      })
      if (res.ok) {
        const data = await res.json()
        setBetCoins('')
        if (data.user) {
          setAuthState(data.user)
        }
        refreshMarket()
      } else {
        const err = await res.json()
        alert(err.error || 'Failed to place bet')
      }
    } catch (e) {
      console.error(e)
    }
    setBetting(false)
  }

  const resolveMarket = async (outcome: 'YES' | 'NO') => {
    try {
      const res = await fetch(`/api/markets/${marketId}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ resolved: true, outcome }),
      })
      if (res.ok) {
        refreshMarket()
        refreshAuth()
      }
    } catch (e) {
      console.error(e)
    }
  }

  if (!marketId) {
    return (
      <div className="max-w-5xl mx-auto px-4 py-8">
        <div className="animate-pulse space-y-4">
          <div className="h-8 bg-[#161b22] rounded w-1/3" />
          <div className="h-64 bg-[#161b22] rounded" />
        </div>
      </div>
    )
  }

  if (isLoading || (!market && !error)) {
    return (
      <div className="max-w-5xl mx-auto px-4 py-8">
        <div className="animate-pulse space-y-4">
          <div className="h-5 bg-[#161b22] rounded w-32" />
          <div className="h-10 bg-[#161b22] rounded w-3/4" />
          <div className="h-24 bg-[#161b22] rounded" />
          <div className="grid grid-cols-1 gap-6 lg:grid-cols-3">
            <div className="h-[420px] rounded bg-[#161b22] lg:col-span-2" />
            <div className="h-[360px] rounded bg-[#161b22]" />
          </div>
        </div>
      </div>
    )
  }

  if (!market) {
    return (
      <div className="max-w-5xl mx-auto px-4 py-8 text-center">
        <p className="text-[#484f58] text-lg">Market not found</p>
        <Link href="/">
          <Button variant="link" className="text-[#58a6ff]">Back to Markets</Button>
        </Link>
      </div>
    )
  }

  const yesPct = market.yesPrice
  const noPct = market.noPrice
  const isCreator = currentUser?.name === market.creatorName
  const yesLabel = market.optionYesLabel || 'Yes'
  const noLabel = market.optionNoLabel || 'No'
  const isClosed = market.closed ?? (!market.resolved && new Date(market.endDate) <= new Date())
  const canBet = market.canBet ?? (!market.resolved && !isClosed)

  const betAmount = parseFloat(betCoins) || 0
  const userBets = currentUser ? market.userBets : []
  const userYesBets = userBets.filter((bet) => bet.choice === 'YES')
  const userNoBets = userBets.filter((bet) => bet.choice === 'NO')
  const activeUserSide = userYesBets.length > 0 ? 'YES' : userNoBets.length > 0 ? 'NO' : null
  const lockedToExistingSide = Boolean(activeUserSide)
  const selectedBetChoice = activeUserSide ?? betChoice
  const currentPrice = (selectedBetChoice === 'YES' ? yesPct : noPct) / 100
  const shares = currentPrice > 0 ? betAmount / currentPrice : 0
  const potentialReturn = shares
  const potentialProfit = potentialReturn - betAmount
  const userYesCoins = userYesBets.reduce((sum, bet) => sum + bet.coins, 0)
  const userNoCoins = userNoBets.reduce((sum, bet) => sum + bet.coins, 0)
  const userYesShares = userYesBets.reduce((sum, bet) => sum + (bet.price > 0 ? bet.coins / bet.price : bet.coins), 0)
  const userNoShares = userNoBets.reduce((sum, bet) => sum + (bet.price > 0 ? bet.coins / bet.price : bet.coins), 0)
  const yesWon = market.resolved && market.outcome === 'YES'
  const noWon = market.resolved && market.outcome === 'NO'

  const userYesProfit = yesWon
    ? userYesShares - userYesCoins
    : market.resolved
      ? -userYesCoins
      : userYesShares - userYesCoins

  const userNoProfit = noWon
    ? userNoShares - userNoCoins
    : market.resolved
      ? -userNoCoins
      : userNoShares - userNoCoins

  // Summary for resolved market
  const totalUserStake = userYesCoins + userNoCoins
  const totalUserReturn = market.resolved
    ? (yesWon ? userYesShares : 0) + (noWon ? userNoShares : 0)
    : 0
  const totalUserProfit = totalUserReturn - totalUserStake
  const betSideLabel = selectedBetChoice === 'YES' ? yesLabel : noLabel

  return (
    <div className="max-w-5xl mx-auto px-4 py-6">
      {/* Breadcrumb */}
      <Link href="/" className="inline-flex items-center text-[#8b949e] hover:text-white text-sm mb-4">
        <ArrowLeft className="w-4 h-4 mr-1" />
        Back to Markets
      </Link>

      {/* Header */}
      <div className="mb-6">
        <div className="flex items-center gap-2 mb-3">
          <Badge variant="secondary" className="bg-[#21262d] text-[#c9d1d9]">{market.category}</Badge>
          {market.resolved ? (
            <Badge className={`${market.outcome === 'YES' ? 'bg-[#238636]/20 text-[#3fb950]' : 'bg-[#da3633]/20 text-[#f85149]'}`}>
              Resolved: {market.outcome === 'YES' ? yesLabel : noLabel}
            </Badge>
          ) : isClosed ? (
            <Badge variant="outline" className="border-[#d29922]/30 text-[#d29922]">Closed</Badge>
          ) : (
            <Badge variant="outline" className="border-[#238636]/30 text-[#3fb950]">Active</Badge>
          )}
        </div>
        <h1 className="text-2xl font-bold text-white mb-2">{market.title}</h1>
        <p className="text-[#8b949e]">{market.description}</p>
        <div className="flex flex-wrap items-center gap-4 mt-3 text-sm text-[#484f58]">
          <div className="flex items-center gap-1">
            <User className="w-3 h-3" />
            Created by {market.creatorName}
          </div>
          <div className="flex items-center gap-1">
            <Clock className="w-3 h-3" />
            Ends {new Date(market.endDate).toLocaleDateString()}
          </div>
          <div className="flex items-center gap-1">
            <Coins className="w-3 h-3" />
            {market.volume.toLocaleString()} Coins Volume
          </div>
          <div className="flex items-center gap-1 text-[#3fb950]">
            <TrendingUp className="w-3 h-3" />
            Liquidity {market.liquidity?.toLocaleString() || 5000}
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Column - Chart & Activity */}
        <div className="lg:col-span-2 space-y-6">
          <Card className="bg-[#161b22] border-[#30363d]">

