'use client'

import useSWR, { mutate, preload } from 'swr'
import type { MarketSummary, MarketDetail } from './market-types'
import type { LeaderboardEntry } from './leaderboard'

export const LEADERBOARD_KEY = '/api/leaderboard'
export const AUTH_KEY = '/api/auth/me'
export const marketKey = (id: string) => `/api/markets/${id}`

type AuthUser = {
  id: string
  name: string
  coins: number
  heldCoins: number
}

type AuthState = {
  user?: AuthUser
}

type SnapshotRecord<T> = {
  expiresAt: number
  value: T
}

const SNAPSHOT_PREFIX = 'twelve-polymarket:swr:'
const memorySnapshots = new Map<string, SnapshotRecord<unknown>>()

const DEFAULT_SNAPSHOT_TTL_MS = 30_000
const AUTH_SNAPSHOT_TTL_MS = 15_000
const LEADERBOARD_SNAPSHOT_TTL_MS = 60_000

function isBrowser() {
  return typeof window !== 'undefined'
}

function getStorageKey(key: string) {
  return `${SNAPSHOT_PREFIX}${key}`
}

function getSnapshotTtlMs(key: string) {
  if (key === AUTH_KEY) return AUTH_SNAPSHOT_TTL_MS
  if (key === LEADERBOARD_KEY) return LEADERBOARD_SNAPSHOT_TTL_MS
  return DEFAULT_SNAPSHOT_TTL_MS
}

function readSnapshot<T>(key: string): T | undefined {
  const now = Date.now()
  const memoryRecord = memorySnapshots.get(key)
  if (memoryRecord && memoryRecord.expiresAt > now) {
    return memoryRecord.value as T
  }

  if (!isBrowser()) return undefined

  try {
    const raw = window.sessionStorage.getItem(getStorageKey(key))
    if (!raw) return undefined

    const record = JSON.parse(raw) as SnapshotRecord<T>
    if (!record || typeof record.expiresAt !== 'number' || record.expiresAt <= now) {
      window.sessionStorage.removeItem(getStorageKey(key))
      memorySnapshots.delete(key)
      return undefined
    }

    memorySnapshots.set(key, record as SnapshotRecord<unknown>)
    return record.value
  } catch {
    return undefined
  }
}

function writeSnapshot<T>(key: string, value: T, ttlMs = getSnapshotTtlMs(key)) {
  const record: SnapshotRecord<T> = {
    value,
    expiresAt: Date.now() + ttlMs,
  }

  memorySnapshots.set(key, record as SnapshotRecord<unknown>)
  if (!isBrowser()) return

  try {
    window.sessionStorage.setItem(getStorageKey(key), JSON.stringify(record))
  } catch {
    // Ignore client storage failures and keep the in-memory snapshot.
  }
}

function clearSnapshot(key: string) {
  memorySnapshots.delete(key)
  if (!isBrowser()) return

  try {
    window.sessionStorage.removeItem(getStorageKey(key))
  } catch {
    // Ignore storage cleanup failures.
  }
}

function getResponseTtlMs(url: string, response: Response) {
  if (url === AUTH_KEY) return AUTH_SNAPSHOT_TTL_MS

  const cacheControl = response.headers.get('cache-control') || ''
  const sMaxAge = cacheControl.match(/s-maxage=(\d+)/)?.[1]
  const maxAge = cacheControl.match(/max-age=(\d+)/)?.[1]
  const seconds = Number(sMaxAge || maxAge)
  if (Number.isFinite(seconds) && seconds > 0) {
    return seconds * 1000
  }

  return getSnapshotTtlMs(url)
}

export const fetcher = async (url: string) => {
  const response = await fetch(url, {
    credentials: 'same-origin',
  })

  if (!response.ok) {
    throw new Error(`Request failed for ${url}: ${response.status}`)
  }

  const data = await response.json()
  writeSnapshot(url, data, getResponseTtlMs(url, response))
  return data
}

const BASE_SWR_CONFIG = {
  refreshInterval: 0,
  revalidateOnFocus: false,
  revalidateIfStale: false,
  keepPreviousData: true,
  revalidateOnReconnect: true,
  dedupingInterval: 10000,
  focusThrottleInterval: 10000,
}

function useCachedSWR<T>(key: string | null, options?: Parameters<typeof useSWR<T>>[2]) {
  const fallbackData = key ? readSnapshot<T>(key) : undefined

  return useSWR<T>(key, fetcher, {
    ...BASE_SWR_CONFIG,
    fallbackData,
    revalidateOnMount: true,
    ...options,
  })
}

export function useMarkets(search?: string, status?: string) {
  const params = new URLSearchParams()
  if (search) params.set('search', search)
  if (status && status !== 'all') params.set('status', status)
  const key = `/api/markets?${params}`

  return useCachedSWR<MarketSummary[]>(key, {
    revalidateOnFocus: true,
    refreshInterval: 30000,
  })
}

export function useMarket(id: string) {
  return useCachedSWR<MarketDetail>(id && id !== '' ? marketKey(id) : null, {
    revalidateOnFocus: true,
    refreshInterval: 15000,
  })
}

export function useLeaderboard() {
  return useCachedSWR<LeaderboardEntry[]>(LEADERBOARD_KEY, {
    refreshInterval: 60000,
  })
}

export function useTrendingMarkets() {
  return useCachedSWR<MarketSummary[]>('/api/markets?status=active', {
    refreshInterval: 30000,
  })
}

export function useAuth() {
  return useCachedSWR<AuthState>(AUTH_KEY, {
    dedupingInterval: 60000,
    focusThrottleInterval: 60000,
  })
}

export function preloadLeaderboardPageData() {
  preload(LEADERBOARD_KEY, fetcher)
}

export function preloadMarketPageData(id: string) {
  if (!id) return
  preload(marketKey(id), fetcher)
}

export function setAuthState(user: AuthUser | null) {
  const nextValue = user ? { user } : {}
  writeSnapshot(AUTH_KEY, nextValue, AUTH_SNAPSHOT_TTL_MS)
  mutate(AUTH_KEY, nextValue, {
    populateCache: true,
    revalidate: false,
  })
}

export function clearAuthState() {
  clearSnapshot(AUTH_KEY)
  mutate(AUTH_KEY, {}, {
    populateCache: true,
    revalidate: false,
  })
}

export function mutateMarkets() {
  return mutate((key) => typeof key === 'string' && key.startsWith('/api/markets'), undefined, {
    revalidate: true,
  })
}

export function mutateMarket(id: string) {
  return mutate(marketKey(id))
}

import { Elysia } from 'elysia'
import type { Prisma } from '@prisma/client'
import { syncUserBalance } from '@/lib/balances'
import { prisma } from '@/lib/prisma'
import { calculateLMSRPrice, DEFAULT_LIQUIDITY } from '@/lib/pricing'
import { asObject, cacheHeaders, getString } from '@/server/http'
import { getSessionUser } from '@/server/session'

const MARKET_BET_PAGE_SIZE = 20
const MAX_MARKET_BET_PAGE_SIZE = 50

type BetVolume = {
  marketId: string
  choice: string
  _sum: {
    coins: number | null
  }
}

type MarketBet = {
  id: string
  userName: string
  coins: number
  choice: string
  price: number
  createdAt: Date
}

function getBetVolumes(volumes: BetVolume[], marketId?: string) {
  const scopedVolumes = marketId ? volumes.filter((volume) => volume.marketId === marketId) : volumes
  const yesVolume = scopedVolumes
    .filter((volume) => volume.choice === 'YES')
    .reduce((sum, volume) => sum + (volume._sum.coins ?? 0), 0)
  const noVolume = scopedVolumes
    .filter((volume) => volume.choice === 'NO')
    .reduce((sum, volume) => sum + (volume._sum.coins ?? 0), 0)

  return { yesVolume, noVolume, totalVolume: yesVolume + noVolume }
}

function serializeBet(bet: MarketBet) {
  return {
    ...bet,
    choice: bet.choice as 'YES' | 'NO',
    createdAt: bet.createdAt.toISOString(),
  }
}

function getBetPageLimit(searchParams: URLSearchParams) {
  const parsed = Number(searchParams.get('limit'))
  if (!Number.isFinite(parsed) || parsed <= 0) return MARKET_BET_PAGE_SIZE
  return Math.min(Math.floor(parsed), MAX_MARKET_BET_PAGE_SIZE)
}

async function getMarketBetPage(marketId: string, searchParams: URLSearchParams) {
  const limit = getBetPageLimit(searchParams)
  const cursor = searchParams.get('cursor')
  const bets = await prisma.bet.findMany({
    where: { marketId },
    orderBy: { createdAt: 'desc' },
    take: limit + 1,
    ...(cursor ? { cursor: { id: cursor }, skip: 1 } : {}),
    select: {
      id: true,
      userName: true,
      coins: true,
      choice: true,
      price: true,
      createdAt: true,
    },
  })
  const pageBets = bets.slice(0, limit)

  return {
    bets: pageBets.map(serializeBet),
    nextCursor: bets.length > limit ? pageBets.at(-1)?.id ?? null : null,
  }
}

async function getMarketSummaries(searchParams: URLSearchParams) {
  const category = searchParams.get('category')
  const search = searchParams.get('search')
  const status = searchParams.get('status')

  const where: Prisma.MarketWhereInput = {}

  if (category && category !== 'All') {
    where.category = category
  }

  if (search) {
    where.OR = [
      { title: { contains: search, mode: 'insensitive' } },
      { description: { contains: search, mode: 'insensitive' } },
    ]
  }

  if (status === 'resolved') {
    where.resolved = true
  } else if (status === 'active') {
    where.resolved = false
  }

  const markets = await prisma.market.findMany({
    where,
    orderBy: { createdAt: 'desc' },
    select: {
      id: true,
      title: true,
      description: true,
      category: true,
      imageUrl: true,
      endDate: true,
      resolved: true,
      outcome: true,
      multiplier: true,
      liquidity: true,
      optionYesLabel: true,
      optionNoLabel: true,
      creatorName: true,
      createdAt: true,
    },
  })
  const volumeRows = markets.length > 0
    ? await prisma.bet.groupBy({
        by: ['marketId', 'choice'],
        where: {
          marketId: {
            in: markets.map((market) => market.id),
          },
        },
        _sum: {
          coins: true,
        },
      })
    : []

  const now = new Date()

  return markets.map((market) => {
    const { yesVolume, noVolume, totalVolume } = getBetVolumes(volumeRows, market.id)
    const liquidity = market.liquidity || DEFAULT_LIQUIDITY
    const { yesPrice, noPrice } = calculateLMSRPrice(yesVolume, noVolume, liquidity)
    const closed = !market.resolved && market.endDate <= now

    return {
      id: market.id,
      title: market.title,
      description: market.description,
      category: market.category,
      imageUrl: market.imageUrl,
      endDate: market.endDate.toISOString(),
      resolved: market.resolved,
      closed,
      canBet: !market.resolved && !closed,
      outcome: market.outcome,
      yesPrice: Math.round(yesPrice * 100),
      noPrice: Math.round(noPrice * 100),
      volume: totalVolume,
      multiplier: market.multiplier,
      optionYesLabel: market.optionYesLabel,
      optionNoLabel: market.optionNoLabel,
      creatorName: market.creatorName,
      createdAt: market.createdAt.toISOString(),
    }
  })
}

async function syncMarketBettorBalances(marketId: string, client: Parameters<Parameters<typeof prisma.$transaction>[0]>[0]) {
  const bettors = await client.bet.findMany({
    where: { marketId },
    distinct: ['userName'],
    select: { userName: true },
  })

  for (const bettor of bettors) {
    await syncUserBalance(bettor.userName, client)
  }
}

export const marketRoutes = new Elysia()
  .get('/api/markets', async ({ request, set }) => {
    try {
      const { searchParams } = new URL(request.url)
      set.headers = cacheHeaders(15)
      return await getMarketSummaries(searchParams)
    } catch {
      set.status = 500
      return { error: 'Failed to fetch markets' }
    }
  })
  .post('/api/markets', async ({ body, request, set }) => {
    try {
