export async function setSession(user: { id: string; name: string }) {
  const cookieStore = await cookies()
  cookieStore.set(SESSION_COOKIE, createSessionToken({ userId: user.id, name: user.name }), {
    httpOnly: true,
    sameSite: 'lax',
    secure: process.env.NODE_ENV === 'production',
    path: '/',
    maxAge: SESSION_MAX_AGE,
  })
}

